import{_ as t,o as i,c as r,ag as o}from"./chunks/framework.ETe_P6d1.js";const s="/kaiping-reports/assets/%E5%9B%BE1.DmICCYDQ.jpg",a="/kaiping-reports/assets/%E5%9B%BE2.Bam6OXTI.jpg",_="/kaiping-reports/assets/%E5%9B%BE3.DALhSioA.jpg",e="/kaiping-reports/assets/%E5%9B%BE4.Bj0clEt7.jpg",g="/kaiping-reports/assets/%E5%9B%BE5.CgiivB5M.jpg",n="/kaiping-reports/assets/%E5%9B%BE6.d5n14tPh.jpg",c="/kaiping-reports/assets/%E5%9B%BE7.C6xbimPs.jpg",m="/kaiping-reports/assets/%E5%9B%BE8.v05klZ0k.jpg",B="/kaiping-reports/assets/%E5%9B%BE9.DZW8BcN6.jpg",l="/kaiping-reports/assets/%E5%9B%BE10.Cx8_scEN.jpg",E="/kaiping-reports/assets/%E5%9B%BE11.CavqYyEk.jpg",k="/kaiping-reports/assets/%E5%9B%BE12.CuTi1iIf.jpg",j="/kaiping-reports/assets/%E5%9B%BE13.4ouWVv3c.jpg",d="/kaiping-reports/assets/%E5%9B%BE14.BKaN1yIA.jpg",D="/kaiping-reports/assets/%E5%9B%BE15.BGlX4Dw2.jpg",C="/kaiping-reports/assets/%E5%9B%BE16.DPZFG7Wg.jpg",f="/kaiping-reports/assets/%E5%9B%BE17.hB9Zdgko.jpg",I="/kaiping-reports/assets/%E5%9B%BE18.Bknn6Cqt.jpg",T="/kaiping-reports/assets/%E5%9B%BE19.cIlknZSh.jpg",v="/kaiping-reports/assets/%E5%9B%BE20.civqNinT.jpg",x="/kaiping-reports/assets/%E5%9B%BE21.Goj7Dqne.jpg",S="/kaiping-reports/assets/%E5%9B%BE22.BJ6iRzmL.jpg",h="/kaiping-reports/assets/%E5%9B%BE23.BBDkyUpI.jpg",u="/kaiping-reports/assets/%E5%9B%BE24.D9LqXxVY.jpg",N="/kaiping-reports/assets/%E5%9B%BE25.C7JvZkSW.jpg",P="/kaiping-reports/assets/%E5%9B%BE26.B0_5Zxrx.jpg",G=JSON.parse('{"title":"立园装饰符号与文化表达调研报告","description":"","frontmatter":{"title":"立园装饰符号与文化表达调研报告"},"headers":[],"relativePath":"reports/胡圳玲/胡圳玲_调研报告.md","filePath":"reports/胡圳玲/胡圳玲_调研报告.md"}'),Z={name:"reports/胡圳玲/胡圳玲_调研报告.md"};function A(q,p,J,V,y,W){return i(),r("div",null,[...p[0]||(p[0]=[o('<p>立园装饰符号与文化表达调研报告 作者：胡圳玲 考察地点：广东省江门市开平市 考察时间：2026 年 4 月 1 日至 2026 年 4 月 2 日 指导教师：石拓教授 一、引言 立园是开平侨乡建筑中装饰最系统、中西融合最典型化、文化表意最完整的华侨私家园林，由旅美华侨谢维立于 1926 至 1936 年兴建，集居住、防御、社交、祭祖、园林观赏于一体，是 20 世纪 30 年代岭南侨乡建筑的巅峰样本。与自力村碉楼的防御优先、仓东村民居的朴素实用、赤坎骑楼的商业街表达不同，立园的装饰并非单纯审美，而是财富展示、身份建构、文化归属、家族伦理、侨民心态的综合载体。 本次报告以立园装饰符号为唯一核心，从装饰类型、材料工艺、构图逻辑、文化寓意、中西拼贴、现代保护与展示六个维度展开专业分析，结合建筑史与文化遗产保护理论，解读立园装饰如何成为 “华侨文化的视觉史书”，并为当代遗产活化与装饰转译提供依据。 二、立园概况与装饰研究价值</p><p><img src="'+s+'" alt="图1：立园鸟瞰图"></p><p>立园占地约 11014 平方米，主体建筑包括泮立楼、泮文楼、炯庐、乐天楼、花棚、曲桥、牌楼、门楼、墓园等，整体布局遵循中国传统园林的 “藏景、框景、借景” 手法，建筑结构以钢筋混凝土为主，外观呈现兼具西式骨架和中式表皮的鲜明特征。 立园装饰的独特价值在于： 系统性：从屋顶到基座、从室外到室内、从结构到构件，装饰全覆盖； 混合性：巴洛克、古典主义、装饰艺术与岭南灰塑、砖雕、陶塑、木刻高度融合； 叙事性：装饰内容围绕家族荣耀、祈福纳祥、忠孝礼义、海外见闻展开，形成完整视觉叙事； 工艺性：集中呈现 20 世纪 30 年代岭南最高水平的灰塑、彩塑、马赛克、铁艺、木作、石刻工艺。 在文化遗产保护的视角下，立园是不可再生的历史信息，其保存状态、修复逻辑、展示方式直接影响遗产原真性与完整性。 三、立园装饰符号的类型与分布 立园装饰可分为结构装饰、构件装饰、界面装饰、陈设装饰四大类，系统覆盖整个园内建筑。 （一）结构装饰：承载功能的形式表达</p><ol><li>山花与檐口</li></ol><p><img src="'+s+'" alt="图2：立泮楼正面"></p><p>泮立楼、乐天楼的顶部都设有巴洛克弧形山花，内部填充灰塑卷草纹、花卉纹；檐口线脚采用西式分层线脚与中式滴水、瓦当组合，体现 “西式轮廓、中式收边”。 2. 柱式与柱头</p><p><img src="'+a+'" alt="图3：科林斯柱"></p><p><img src="'+_+'" alt="图4：混合柱式"></p><p>立柱以罗马柱、塔司干柱、爱奥尼柱为主，柱头简化处理，放弃复杂茛苕叶，改用中式花卉、蝙蝠、如意图案，实现 “西式结构、中式表意”。 3. 拱券与门窗</p><p><img src="'+e+'" alt="图5：窗框"></p><p><img src="'+g+'" alt="图6：窗框"></p><p>门窗多为半圆拱、平拱，在拱心石位置雕刻了福、禄、寿、喜等字样或花卉，将西式力学节点与中式祈福符号相结合。满洲窗的彩色玻璃在立园室内外交界处形成戏剧性的光影效果，突破了传统木构的沉静。 （二）构件装饰：细节处的文化拼贴</p><ol><li>屋顶装饰</li></ol><p><img src="'+n+'" alt="图7：屋顶"></p><p>主体建筑采用中式硬山顶、歇山顶，铺青瓦，屋脊施灰塑双龙戏珠、双凤朝阳、卷草纹；局部小建筑用西式四坡顶，形成 “主楼守传统、配楼求变化” 的装饰特点。 2. 栏杆装饰</p><p><img src="'+c+'" alt="图8：瓶式栏杆"></p><p><img src="'+m+'" alt="图9：花格栏杆"></p><p><img src="'+B+'" alt="图10：铁艺栏杆"></p><p>阳台、楼梯、花架栏杆分三种：西式瓶式栏杆（水泥预制）；中式镂空花格栏杆（几何纹、冰裂纹）；混合式铁艺 + 水泥花饰，图案含蝙蝠、梅花、铜钱。 3. 门楼与牌楼</p><p><img src="'+l+'" alt="图11：入口牌楼"></p><p>入口牌楼为三间四柱中式形制，匾额题字 “立园”，柱身饰西式壁柱与花环浮雕，内外两套语言，对外展示中式身份，对内呈现西式审美。 （三）界面装饰：墙面与地面的视觉系统</p><ol><li>外墙装饰</li></ol><p><img src="'+E+'" alt="图12：外墙"></p><p>主体是青砖清水墙，局部红砖点缀；重点部位用彩色马赛克拼花（几何纹、花卉纹）装饰，材料多进口自欧美，体现了华侨的财力；阴影区用水泥拉毛、仿石抹灰，强化了光影层次。 2. 内墙装饰</p><p><img src="'+k+'" alt="图13：室内彩画"></p><p>室内设墙裙、石膏线、彩画，题材多为山水、花鸟、戏曲故事，工艺上融合了岭南壁画和西式油彩。 3. 地面装饰</p><p><img src="'+j+'" alt="图14：马赛克地砖"></p><p><img src="'+d+'" alt="图15：马赛克地砖"></p><p>厅堂用水泥花砖、马赛克拼花做装饰，庭院用卵石铺成福字、寿字、几何纹，步行路径兼具引导性与寓意性。 （四）陈设装饰：室内空间的身份表达</p><p><img src="'+D+'" alt="图16：中式家具"></p><p>室内的木隔断、屏风、罩、挂落均装饰有中式传统纹样（梅兰竹菊、松鹤延年、鸳鸯戏水），隔扇、神龛雕刻有 “八仙过海”“郭子仪祝寿” 等传统戏曲场景，家具为西式沙发、中式酸枝木混用，装饰与家具共同构建了一幅 “中西合璧” 的生活画面。 四、立园装饰的材料、工艺与建造框架</p><p><img src="'+C+'" alt="图17：水泥灰塑"></p><p><img src="'+f+'" alt="图18：马赛克"></p><p><img src="'+I+'" alt="图19：陶塑"></p><p>立园装饰以水泥灰塑、马赛克、砖雕、铁艺、木刻、石刻为核心，反映 “现代技术 + 传统审美” 的建造智慧。 （一）核心工艺</p><ol><li>灰塑（岭南非遗） 材料：石灰、稻草、纸筋、矿物颜料； 位置：屋脊、檐口、山墙、照壁； 特点：耐风雨、可塑性强、色彩持久； 主题：以吉祥图案为主，如石榴（多子多福）、蝙蝠（福至）、卷草纹（生生不息），强调祈福、镇宅、家族延续。</li><li>马赛克与水泥花砖 来源：进口意大利、德国马赛克，本地定制水泥花砖； 功能：防水、耐磨、易清洁，适应岭南多雨气候； 美学：几何秩序强，与中式自由纹样形成对比。</li><li>铁艺与预制混凝土 铁艺：栏杆、大门、窗栅，图案简化流畅，兼具防御与装饰； 预制混凝土：批量生产柱头、花瓶栏杆，效率高、整体性强，体现近代建筑工业化特征。 （二）建造框架：内新外旧、功能优先 立园装饰体现三条规律： 结构现代化，装饰承袭传统：建筑结构大范围使用钢筋混凝土以保证安全与跨度，外观用中式传统符号维持文化认同； 公共面重装饰，私密面简约：临街、庭院可视面装饰繁复，后院、仆役区风格简洁； 重视文化寓意：处处体现着吉祥、身份与伦理表达。 五、立园装饰的文化寓意与华侨心态 立园装饰不是形式堆砌，而是华侨身份与价值观的视觉宣言，可解读为四层表意系统。 （一）家国归属：中式符号的文化坚守 题材以儒家伦理为核心：忠孝、福禄、长寿、和合、家族兴旺； 文字装饰强化身份：匾额、楹联、题字多为家训、格言、山水诗文，强调中式教化； 园林符号延续传统：假山、水池、曲桥、花窗，遵循江南与岭南园林审美。 （二）现代性表达：西式符号的时代追求 柱式、拱券、山花体现 “文明、进步、海外视野”； 马赛克、水泥花砖、铁艺代表 “新材料、新技术、新生活方式”； 对称构图、几何秩序代表西方理性美学，与中式自由写意互补。 （三）侨民心态：双重文化的妥协与融合 立园装饰最核心的文化意义，在于呈现华侨的双重身份：身在海外，认同西方现代文明；根在乡土，坚守中式伦理与审美。西式符号用于展示现代与财富，中式符号用于锚定文化与家族，两者并置不冲突，形成独特的 “侨乡美学”。 （四）社会象征：财富、地位与家族荣耀 进口材料、工艺复杂、大面积装饰，直接展示华侨经济实力；建筑以家族成员名字命名（泮立、泮文），装饰围绕家族叙事，强化宗族凝聚力与社会声望。 六、中西装饰融合的机制与建筑史上的意义 从建筑史视角看，立园装饰并非 “混搭”，而是有规则的融合策略，可归纳为三种模式。 （一）位置分治：外西内中</li></ol><p><img src="'+T+'" alt="图20：外立面"></p><p><img src="'+v+'" alt="图21：木雕"></p><p>外立面、结构构件以西式为主（柱、拱、山花）；内庭院、屋顶、室内则以中式为主（灰塑、木刻、匾额）。 （二）功能分治：结构西化，表意中式 承重、力学节点采用了西式的形式（拱心石、柱头）；文化、伦理、祈福则体现了中式题材（花鸟、文字、瑞兽）。 （三）风格简化：双向妥协</p><p><img src="'+x+'" alt="图22：西式柱头和灰塑"></p><p><img src="'+S+'" alt="图23：西式柱头和灰塑"></p><p>西式纹样简化：放弃复杂巴洛克雕刻，转向几何化、线条化； 中式纹样简化：灰塑更简洁，适应混凝土施工。 这种融合在近代中国建筑史上具有典型意义：立园代表了民间精英阶层对传统与现代的自主选择，不同于租界建筑的强制西化，也不同于乡村建筑的保守固守，是本土文化主动吸纳外来文明的珍贵样本。 七、遗产保护视角：立园装饰的现状、问题与保护策略</p><p><img src="'+h+'" alt="图24：立泮楼"></p><p><img src="'+u+'" alt="图25：炯庐"></p><p><img src="'+N+'" alt="图26：乐天楼"></p><p>立园现为博物馆化保护模式，装饰层是最脆弱、信息最丰富的遗产部分，保护面临多重挑战。 （一）保存现状 整体完好：主体装饰未受大规模破坏； 局部损伤：灰塑褪色、剥落、风化；马赛克空鼓、脱落；木构件开裂、虫蛀； 修复痕迹：部分区域采用现代涂料补色，与原工艺色差明显，原真性受损。 （二）核心问题 风化与老化：岭南高温高湿多雨，加速有机材料与矿物颜料衰退； 修复工艺失传：传统灰塑、彩塑匠人减少，现代修复难以还原质感； 研究不足：对装饰题材、匠人、工艺流程、图像叙事的系统研究仍薄弱。 （三）保护原则与策略 最小干预：优先加固、防风化，不轻易重造、重绘； 可识别修复：补配部分与原构件明显区分，不误导历史信息； 可逆性：修复材料可移除，不破坏原构件； 数字化存档：激光扫描、摄影测量建立三维数据库； 展示管控：设置防护栏、控制灯光、限制近距离接触，平衡参观与保护。 八、装饰符号的当代转译：从遗产到设计启发 立园装饰对当代建筑与设计具有直接借鉴价值，可实现传统活化而非符号复制。 （一）可转译的核心元素 构图逻辑：对称与均衡、重点突出、层次递进； 寓意机制：将现代价值观（生态、创新、包容）转化为视觉符号； 气候适应性：马赛克、镂空、遮阳构件的现代材料迭代； 中西融合方法：结构现代、表皮文化，避免生硬复古。 （二）转译路径 抽象转译：提取卷草、如意、几何纹的线条与比例，用于现代立面、景观、室内； 叙事转译：延续 “空间讲故事” 思路，用现代装饰承载地域文化与社区记忆。 九、总结</p><p><img src="'+P+'" alt="图27：水塘"></p><p>立园装饰是开平侨乡文化最浓缩、最精美的视觉载体，它以系统的符号系统、精湛的工艺、清晰的中西融合逻辑、深刻的华侨文化寓意，成为近代中国建筑史的关键样本。其价值不仅在于审美与工艺，更在于记录了华侨在传统与现代、本土与海外之间的身份建构过程。 从文化遗产保护角度，立园装饰的保护必须坚持原真性、最小干预、可识别、可逆性，以数字化技术永久保存信息，以科学修复延续生命。从设计角度，立园提供了传统不复古、现代不冷漠的融合范式，通过形态、材料与装饰语言的融合，创造出具有在地性情感与跨文化包容性的空间，其装饰逻辑、构图方法、寓意表达可直接转译为当代设计语言。 立园的装饰告诉我们：遗产保护不是冻结历史，而是理解背后的文化逻辑，让传统符号在当代继续讲述属于这片土地的故事。开平碉楼与村落的世界遗产价值，正蕴藏在这些精美的装饰细节之中。 十、附录：调研记录 （一）摄影记录 本报告共插入 26 张现场照片，1 张网络图片，分别展示： 图 1：立园鸟瞰图 图 2 - 图 26：立园主立面与内部空间 图 27：立园水塘景观 （二）文献资料 参考书目： 曾丽娟。繁华褪去，古韵留今 —— 岭南华侨园林装饰艺术特征研究 /[J]. 文化月刊，2019,(05):135-137. 薛颖。近代岭南建筑装饰研究 /[D]. 华南理工大学，2012. 薛颖，甘芝。近代岭南教堂的中西融合特征研究 —— 以江门为例 /[J]. 建筑与文化，2026,(02):228-231.DOI:10.19875/j.cnki.jzywh.2026.02.069. 报告撰写人：胡圳玲 报告完成时间：2026 年 4 月 19 日 字数统计：约 3300 字</p>',48)])])}const L=t(Z,[["render",A]]);export{G as __pageData,L as default};
